import{_ as e,o as i,c as s,ag as a}from"./chunks/framework.5wcOFaQl.js";const k=JSON.parse('{"title":"ComfyUI Skill 🎨","description":"","frontmatter":{},"headers":[],"relativePath":"comfyui-guide.md","filePath":"comfyui-guide.md"}'),n={name:"comfyui-guide.md"};function r(l,t,h,d,o,p){return i(),s("div",null,[...t[0]||(t[0]=[a(`<h1 id="comfyui-skill-🎨" tabindex="-1">ComfyUI Skill 🎨 <a class="header-anchor" href="#comfyui-skill-🎨" aria-label="Permalink to &quot;ComfyUI Skill 🎨&quot;">​</a></h1><p>Der <strong>ComfyUI Skill</strong> ist seit Hermes <strong>v0.12.0</strong> (Curator Release, 30. April 2026) standardmäßig eingebaut. Er ermöglicht Hermes, ComfyUI zu installieren, zu starten und Workflows auszuführen.</p><blockquote><p><strong>Hinweis:</strong> Der Skill ist sehr neu – es gibt noch wenig öffentliche Erfahrungsberichte. Die folgenden Infos basieren auf eigener Nutzung mit ROCm / AMD Radeon.</p></blockquote><hr><h2 id="🚀-funktionen" tabindex="-1">🚀 Funktionen <a class="header-anchor" href="#🚀-funktionen" aria-label="Permalink to &quot;🚀 Funktionen&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Feature</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Installation</strong></td><td style="text-align:left;"><code>comfy-cli</code> + hardware-gated lokale Installation</td></tr><tr><td style="text-align:left;"><strong>Node-Management</strong></td><td style="text-align:left;">Nodes/Models verwalten</td></tr><tr><td style="text-align:left;"><strong>Workflow-Ausführung</strong></td><td style="text-align:left;">Workflows laden, Parameter injizieren, ausführen</td></tr><tr><td style="text-align:left;"><strong>Medientypen</strong></td><td style="text-align:left;">Bilder, Video, Audio</td></tr><tr><td style="text-align:left;"><strong>Cloud/Cloud</strong></td><td style="text-align:left;">Comfy Cloud (API-Key nötig) oder lokal</td></tr></tbody></table><hr><h2 id="⚙️-konfiguration" tabindex="-1">⚙️ Konfiguration <a class="header-anchor" href="#⚙️-konfiguration" aria-label="Permalink to &quot;⚙️ Konfiguration&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Bereich</th><th style="text-align:left;">Details</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Version</strong></td><td style="text-align:left;">ComfyUI v0.20.1</td></tr><tr><td style="text-align:left;"><strong>GPU</strong></td><td style="text-align:left;">RX 9060 XT (16 GB VRAM, ROCm 6.3)</td></tr><tr><td style="text-align:left;"><strong>Torch</strong></td><td style="text-align:left;">2.9.1+rocm6.3</td></tr><tr><td style="text-align:left;"><strong>Modelle</strong></td><td style="text-align:left;">SDXL Base (6,5 GB) – stabil; ACE Step 1.5 Turbo (9,4 GB) – instabil</td></tr><tr><td style="text-align:left;"><strong>Server-Port</strong></td><td style="text-align:left;">8188</td></tr><tr><td style="text-align:left;"><strong>Bildergalerie</strong></td><td style="text-align:left;">Port 8765 (siehe unten)</td></tr></tbody></table><hr><h2 id="🖼️-bildergalerie" tabindex="-1">🖼️ Bildergalerie <a class="header-anchor" href="#🖼️-bildergalerie" aria-label="Permalink to &quot;🖼️ Bildergalerie&quot;">​</a></h2><p>Die ComfyUI-Oberfläche ist gewöhnungsbedürftig. Alternative: Eigener Bilder-Viewer:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Starten (im Hintergrund)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/comfy/ComfyUI/output</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http.server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8765</span></span></code></pre></div><p>Dann im Browser öffnen: <strong><a href="http://127.0.0.1:8765/galerie.html" target="_blank" rel="noreferrer">http://127.0.0.1:8765/galerie.html</a></strong></p><blockquote><p>Die Galerie zeigt alle generierten Bilder als Raster. Einfach draufklicken zum Vergrößern.</p></blockquote><hr><h2 id="⚠️-bekannte-probleme-rocm-rx-9060-xt" tabindex="-1">⚠️ Bekannte Probleme (ROCm / RX 9060 XT) <a class="header-anchor" href="#⚠️-bekannte-probleme-rocm-rx-9060-xt" aria-label="Permalink to &quot;⚠️ Bekannte Probleme (ROCm / RX 9060 XT)&quot;">​</a></h2><h3 id="_1-zweite-generierung-crasht-den-server" tabindex="-1">1. Zweite Generierung crasht den Server <a class="header-anchor" href="#_1-zweite-generierung-crasht-den-server" aria-label="Permalink to &quot;1. Zweite Generierung crasht den Server&quot;">​</a></h3><p><strong>Problem:</strong> Nach einer erfolgreichen ersten Bildgenerierung stürzt ComfyUI beim zweiten Prompt ab (Port 8188 nicht mehr erreichbar, &quot;error reconnecting&quot; in der UI).</p><p><strong>Ursache:</strong> Vermutlich VRAM-Fragmentierung oder ROCm-Treiber-Problem auf der RX 9060 XT (16 GB).</p><p><strong>Lösung:</strong> Nach jedem Bild den Server neustarten:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># PID aus /tmp/comfyui.pid lesen (falls vorhanden)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">kill</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/comfyui.pid</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Oder per ps finden</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aux</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;python main.py&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grep</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> awk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{print $2}&#39;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">kill</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">PI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">D</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Neu starten</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/comfy/ComfyUI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .venv/bin/activate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.py</span></span></code></pre></div><p><strong>Workaround per API:</strong> Vor dem zweiten Prompt VRAM freigeben:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8188/free</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;unload_models&quot;:true,&quot;free_memory&quot;:true}&#39;</span></span></code></pre></div><p>Hilft nicht immer, aber manchmal.</p><h3 id="_2-ace-step-1-5-turbo-9-4-gb-instabil" tabindex="-1">2. ACE Step 1.5 Turbo (9,4 GB) instabil <a class="header-anchor" href="#_2-ace-step-1-5-turbo-9-4-gb-instabil" aria-label="Permalink to &quot;2. ACE Step 1.5 Turbo (9,4 GB) instabil&quot;">​</a></h3><p>Das große Bildbearbeitungs-Modell lädt oft nicht oder stürzt ab.</p><p><strong>Lösung:</strong> SDXL Base (6,5 GB) nutzen – läuft stabil.</p><h3 id="_3-serverseitiger-start-uber-hermes" tabindex="-1">3. Serverseitiger Start über Hermes <a class="header-anchor" href="#_3-serverseitiger-start-uber-hermes" aria-label="Permalink to &quot;3. Serverseitiger Start über Hermes&quot;">​</a></h3><p>Wenn Hermes ComfyUI per <code>terminal(background=true)</code> startet, kommt oft kein Output/Log und der Server ist nicht erreichbar. Manueller Start in einem echten Terminal funktioniert zuverlässig.</p><h3 id="_4-pid-datei-nicht-immer-vorhanden" tabindex="-1">4. PID-Datei nicht immer vorhanden <a class="header-anchor" href="#_4-pid-datei-nicht-immer-vorhanden" aria-label="Permalink to &quot;4. PID-Datei nicht immer vorhanden&quot;">​</a></h3><p><code>/tmp/comfyui.pid</code> existiert nicht nach jedem Start. Alternativ per <code>ps aux | grep python main.py</code> die PID finden.</p><hr><h2 id="💡-tipps" tabindex="-1">💡 Tipps <a class="header-anchor" href="#💡-tipps" aria-label="Permalink to &quot;💡 Tipps&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Situation</th><th style="text-align:left;">Lösung</th></tr></thead><tbody><tr><td style="text-align:left;">ComfyUI startet nicht</td><td style="text-align:left;">In echtem Terminal starten, nicht per Hermes-Background</td></tr><tr><td style="text-align:left;">Zweites Bild</td><td style="text-align:left;">Vorher VRAM free + Server neustarten</td></tr><tr><td style="text-align:left;">Bilder ansehen</td><td style="text-align:left;">Galerie auf Port 8765 statt ComfyUI-UI</td></tr><tr><td style="text-align:left;">ACE Step testen</td><td style="text-align:left;">Besser SDXL verwenden</td></tr><tr><td style="text-align:left;">Prompt eingeben</td><td style="text-align:left;">Per API an ComfyUI senden (einfacher als die GUI)</td></tr></tbody></table><hr><h2 id="🔗-verwandte-seiten" tabindex="-1">🔗 Verwandte Seiten <a class="header-anchor" href="#🔗-verwandte-seiten" aria-label="Permalink to &quot;🔗 Verwandte Seiten&quot;">​</a></h2><ul><li><a href="/hermes-compendium/skills.html">Skills-Übersicht</a></li><li><a href="/hermes-compendium/tipps.html">Tipps &amp; Tricks</a></li><li><a href="/hermes-compendium/troubleshooting.html">Troubleshooting</a></li></ul>`,38)])])}const u=e(n,[["render",r]]);export{k as __pageData,u as default};
